# Assume the database layer is already implemented
# and provides the following functions:
# - create_list(list_name): Creates a new todo list. Returns list_id.
# - get_list(list_id): Returns a list object (name, items).
# - update_list(list_id, new_name): Updates the list name.
# - delete_list(list_id): Deletes the list.
# - create_item(list_id, item_text, due_date=None): Creates a new item in a list. Returns item_id.
# - get_item(item_id): Returns an item object (text, completed, due_date).
# - update_item(item_id, new_text=None, completed=None, due_date=None): Updates an item.
# - delete_item(item_id): Deletes an item.
# - get_all_lists(): Returns a list of all list objects (id, name).
# - get_items_for_list(list_id): Returns a list of item objects for a given list.
# - mark_item_complete(item_id): Marks an item as complete.
# - mark_item_incomplete(item_id): Marks an item as incomplete.

# Example database functions (replace with your actual implementation)
lists = {}
items = {}
list_id_counter = 1
item_id_counter = 1

def create_list(list_name):
    global list_id_counter
    lists[list_id_counter] = {"name": list_name, "items": []}
    list_id = list_id_counter
    list_id_counter += 1
    return list_id

def get_list(list_id):
    if list_id in lists:
        return lists[list_id]
    return None

def update_list(list_id, new_name):
    if list_id in lists:
        lists[list_id]["name"] = new_name
        return True
    return False

def delete_list(list_id):
    if list_id in lists:
        del lists[list_id]
        # Also delete items associated with the list (not strictly necessary for the API, but good practice)
        items_to_delete = []
        for item_id, item in items.items():
            if item["list_id"] == list_id:
                items_to_delete.append(item_id)
        for item_id in items_to_delete:
            del items[item_id]
        return True
    return False

def create_item(list_id, item_text, due_date=None):
    global item_id_counter
    if list_id in lists:
        items[item_id_counter] = {"list_id": list_id, "text": item_text, "completed": False, "due_date": due_date}
        item_id = item_id_counter
        item_id_counter += 1
        return item_id
    return None

def get_item(item_id):
    if item_id in items:
        return items[item_id]
    return None

def update_item(item_id, new_text=None, completed=None, due_date=None):
    if item_id in items:
        if new_text is not None:
            items[item_id]["text"] = new_text
        if completed is not None:
            items[item_id]["completed"] = completed
        if due_date is not None:
            items[item_id]["due_date"] = due_date
        return True
    return False

def delete_item(item_id):
    if item_id in items:
        del items[item_id]
        return True
    return False

def get_all_lists():
    result = []
    for list_id, list_data in lists.items():
        result.append({"id": list_id, "name": list_data["name"]})
    return result

def get_items_for_list(list_id):
    result = []
    for item_id, item_data in items.items():
        if item_data["list_id"] == list_id:
            item_data_copy = item_data.copy()
            item_data_copy["id"] = item_id
            result.append(item_data_copy)
    return result

def mark_item_complete(item_id):
    return update_item(item_id, completed=True)

def mark_item_incomplete(item_id):
    return update_item(item_id, completed=False)


# API Endpoints

@app.route('/lists', methods=['POST'])
def create_new_list():
    data = request.get_json()
    if 'name' not in data:
        return jsonify({'message': 'List name is required'}), 400
    list_id = create_list(data['name'])
    return jsonify({'id': list_id, 'message': 'List created successfully'}), 201

@app.route('/lists/<int:list_id>', methods=['GET'])
def get_existing_list(list_id):
    todo_list = get_list(list_id)
    if not todo_list:
        return jsonify({'message': 'List not found'}), 404

    items = get_items_for_list(list_id)
    todo_list_copy = todo_list.copy()
    todo_list_copy['items'] = items
    todo_list_copy['id'] = list_id

    return jsonify(todo_list_copy), 200

@app.route('/lists/<int:list_id>', methods=['PUT'])
def update_existing_list(list_id):
    data = request.get_json()
    if 'name' not in data:
        return jsonify({'message': 'New list name is required'}), 400
    if update_list(list_id, data['name']):
        return jsonify({'message': 'List updated successfully'}), 200
    else:
        return jsonify({'message': 'List not found'}), 404

@app.route('/lists/<int:list_id>', methods=['DELETE'])
def delete_existing_list(list_id):
    if delete_list(list_id):
        return jsonify({'message': 'List deleted successfully'}), 200
    else:
        return jsonify({'message': 'List not found'}), 404

@app.route('/lists', methods=['GET'])
def get_all_todo_lists():
    all_lists = get_all_lists()
    return jsonify(all_lists), 200

@app.route('/lists/<int:list_id>/items', methods=['POST'])
def create_new_item(list_id):
    data = request.get_json()
    if 'text' not in data:
        return jsonify({'message': 'Item text is required'}), 400
    due_date = data.get('due_date')  # Optional due date
    item_id = create_item(list_id, data['text'], due_date)
    if item_id:
        return jsonify({'id': item_id, 'message': 'Item created successfully'}), 201
    else:
        return jsonify({'message': 'List not found'}), 404

@app.route('/items/<int:item_id>', methods=['GET'])
def get_existing_item(item_id):
    item = get_item(item_id)
    if not item:
        return jsonify({'message': 'Item not found'}), 404
    item_copy = item.copy()
    item_copy['id'] = item_id
    return jsonify(item_copy), 200

@app.route('/items/<int:item_id>', methods=['PUT'])
def update_existing_item(item_id):
    data = request.get_json()
    new_text = data.get('text')
    completed = data.get('completed')
    due_date = data.get('due_date')

    if update_item(item_id, new_text, completed, due_date):
        return jsonify({'message': 'Item updated successfully'}), 200
    else:
        return jsonify({'message': 'Item not found'}), 404

@app.route('/items/<int:item_id>', methods=['DELETE'])
def delete_existing_item(item_id):
    if delete_item(item_id):
        return jsonify({'message': 'Item deleted successfully'}), 200
    else:
        return jsonify({'message': 'Item not found'}), 404

@app.route('/items/<int:item_id>/complete', methods=['PUT'])
def complete_item(item_id):
    if mark_item_complete(item_id):
        return jsonify({'message': 'Item marked as complete'}), 200
    else:
        return jsonify({'message': 'Item not found'}), 404

@app.route('/items/<int:item_id>/incomplete', methods=['PUT'])
def incomplete_item(item_id):
    if mark_item_incomplete(item_id):
        return jsonify({'message': 'Item marked as incomplete'}), 200
    else:
        return jsonify({'message': 'Item not found'}), 404

@app.route('/progress/<int:list_id>', methods=['GET'])
def get_list_progress(list_id):
    todo_list = get_list(list_id)
    if not todo_list:
        return jsonify({'message': 'List not found'}), 404

    items = get_items_for_list(list_id)
    total_items = len(items)
    completed_items = sum(1 for item in items if item['completed'])

    if total_items == 0:
        progress = 0
    else:
        progress = (completed_items / total_items) * 100

    return jsonify({
        'list_id': list_id,
        'list_name': todo_list['name'],
        'total_items': total_items,
        'completed_items': completed_items,
        'progress': progress
    }), 200

@app.route('/reminders', methods=['GET'])
def get_reminders():
    today = datetime.now().date()
    reminders = []
    for item_id, item in items.items():
        if item['due_date']:
            due_date = datetime.strptime(item['due_date'], '%Y-%m-%d').date()
            if not item['completed']:
                if due_date <= today:
                    list_data = get_list(item['list_id'])
                    list_name = list_data['name'] if list_data else "Unknown List"
                    status = "Due" if due_date == today else "Overdue"
                    reminders.append({
                        'item_id': item_id,
                        'list_name': list_name,
                        'text': item['text'],
                        'due_date': item['due_date'],
                        'status': status
                    })
    return jsonify(reminders), 200

if __name__ == '__main__':
    app.run(debug=True)

