from flask import Flask, request, jsonify
from datetime import datetime, timedelta
import uuid

app = Flask(__name__)

# Assume a pre-existing database layer with the following functions:
# - create_list(list_name): Creates a new list and returns its ID.
# - get_list(list_id): Returns a list object (name, tasks).
# - update_list(list_id, list_name): Updates the list name.
# - delete_list(list_id): Deletes a list.
# - create_task(list_id, task_name, due_date=None): Creates a new task in a list.
# - get_task(task_id): Returns a task object (name, due_date, completed).
# - update_task(task_id, task_name=None, due_date=None, completed=None): Updates a task.
# - delete_task(task_id): Deletes a task.
# - get_tasks_for_list(list_id): Returns a list of tasks for a given list.
# - get_overdue_tasks(): Returns a list of overdue tasks.
# - get_upcoming_tasks(days=7): Returns a list of tasks due in the next 'days' days.

# Example Database Layer (replace with your actual implementation)
class MockDatabase:
    def __init__(self):
        self.lists = {}
        self.tasks = {}
        self.list_id_counter = 1
        self.task_id_counter = 1

    def create_list(self, list_name):
        list_id = self.list_id_counter
        self.lists[list_id] = {"name": list_name, "tasks": []}
        self.list_id_counter += 1
        return list_id

    def get_list(self, list_id):
        if list_id in self.lists:
            return self.lists[list_id]
        return None

    def update_list(self, list_id, list_name):
        if list_id in self.lists:
            self.lists[list_id]["name"] = list_name
            return True
        return False

    def delete_list(self, list_id):
        if list_id in self.lists:
            del self.lists[list_id]
            # Also delete tasks associated with the list
            task_ids_to_delete = []
            for task_id, task in self.tasks.items():
                if task["list_id"] == list_id:
                    task_ids_to_delete.append(task_id)
            for task_id in task_ids_to_delete:
                del self.tasks[task_id]
            return True
        return False

    def create_task(self, list_id, task_name, due_date=None):
        if list_id not in self.lists:
            return None
        task_id = self.task_id_counter
        self.tasks[task_id] = {"list_id": list_id, "name": task_name, "due_date": due_date, "completed": False}
        self.lists[list_id]["tasks"].append(task_id)
        self.task_id_counter += 1
        return task_id

    def get_task(self, task_id):
        if task_id in self.tasks:
            return self.tasks[task_id]
        return None

    def update_task(self, task_id, task_name=None, due_date=None, completed=None):
        if task_id in self.tasks:
            if task_name is not None:
                self.tasks[task_id]["name"] = task_name
            if due_date is not None:
                self.tasks[task_id]["due_date"] = due_date
            if completed is not None:
                self.tasks[task_id]["completed"] = completed
            return True
        return False

    def delete_task(self, task_id):
        if task_id in self.tasks:
            list_id = self.tasks[task_id]["list_id"]
            self.lists[list_id]["tasks"].remove(task_id)
            del self.tasks[task_id]
            return True
        return False

    def get_tasks_for_list(self, list_id):
        if list_id in self.lists:
            task_ids = self.lists[list_id]["tasks"]
            return [self.tasks[task_id] for task_id in task_ids if task_id in self.tasks]
        return []

    def get_overdue_tasks(self):
        now = datetime.now()
        overdue_tasks = []
        for task_id, task in self.tasks.items():
            if task["due_date"] and datetime.strptime(task["due_date"], "%Y-%m-%d") < now and not task["completed"]:
                overdue_tasks.append(task)
        return overdue_tasks

    def get_upcoming_tasks(self, days=7):
        now = datetime.now()
        upcoming_tasks = []
        for task_id, task in self.tasks.items():
            if task["due_date"]:
                due_date = datetime.strptime(task["due_date"], "%Y-%m-%d")
                if now <= due_date <= now + timedelta(days=days) and not task["completed"]:
                    upcoming_tasks.append(task)
        return upcoming_tasks

