@app.route('/lists', methods=['POST'])
def create_list():
    """
    Creates a new task list.
    """
    data = request.get_json()
    name = data.get('name')
    if not name:
        return jsonify({'message': 'List name is required'}), 400

    new_list_id = db.create_list(name)
    return jsonify({'message': 'List created', 'list_id': new_list_id}), 201

@app.route('/lists/<int:list_id>', methods=['PUT'])
def update_list(list_id):
    """
    Updates an existing task list.
    """
    try:
        data = request.get_json()
        name = data.get('name')
        if not name:
            return jsonify({'message': 'List name is required'}), 400

        db.update_list(list_id, name)
        return jsonify({'message': 'List updated'}), 200
    except ListNotFoundError as e:
        raise e

