@app.route('/lists/<int:list_id>/tasks', methods=['POST'])
def create_task(list_id):
    """
    Creates a new task in a specific list.
    """
    try:
        data = request.get_json()
        description = data.get('description')
        due_date_str = data.get('due_date')  # Expecting ISO format (YYYY-MM-DD)
        completed = data.get('completed', False)

        if not description:
            return jsonify({'message': 'Task description is required'}), 400

        due_date = None
        if due_date_str:
            try:
                due_date = datetime.fromisoformat(due_date_str)
            except ValueError:
                return jsonify({'message': 'Invalid date format. Use YYYY-MM-DD'}), 400

        new_task_id = db.create_task(list_id, description, due_date, completed)
        return jsonify({'message': 'Task created', 'task_id': new_task_id}), 201
    except ListNotFoundError as e:
        raise e

