@app.route('/progress', methods=['GET'])
def get_progress():
    """
    Provides a progress overview.  Returns total tasks, completed tasks,
    and percentage complete.
    """
    total_tasks = db.get_total_tasks()
    completed_tasks = db.get_completed_tasks()

    if total_tasks == 0:
        percentage_complete = 0
    else:
        percentage_complete = (completed_tasks / total_tasks) * 100

    return jsonify({
        'total_tasks': total_tasks,
        'completed_tasks': completed_tasks,
        'percentage_complete': percentage_complete
    }), 200

@app.route('/notifications', methods=['GET'])
def get_notifications():
    """
    Retrieves notifications for tasks approaching or past their deadline.
    """
    upcoming_tasks = db.get_upcoming_tasks(days=2)  # Tasks due in the next 2 days
    overdue_tasks = db.get_overdue_tasks()

    notifications = []

    for task in upcoming_tasks:
        notifications.append({
            'message': f'Task "{task["description"]}" is due on {task["due_date"]}',
            'task_id': task['id'],
            'type': 'upcoming'
        })

    for task in overdue_tasks:
        notifications.append({
            'message': f'Task "{task["description"]}" is overdue. It was due on {task["due_date"]}',
            'task_id': task['id'],
            'type': 'overdue'
        })

    return jsonify(notifications), 200

